const css = document.createElement('link'); css.rel = 'stylesheet';
css.href = 'https://cdn.jsdelivr.net/npm/tufte-css@1.9.0/tufte.min.css';
const el = document.createElement('article'); el.style.maxWidth = `${data.max_width ?? 1400}px`;
el.innerHTML = data.html;
shadowRoot.append(css, el);

